<template>
  <svg xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="none"  x="0px" y="0px"  xml:space="preserve" :style="{'overflow': 'visible','width':(detail && detail.style && detail.style.position && detail.style.position.w) || '200px','height':(detail && detail.style && detail.style.position && detail.style.position.h) || '200px'}">
    <g class="svg-el" :style="{'opacity':fillOpacity,'stroke-opacity':strokeOpacity,'stroke':strokeColor,'stroke-width':strokeWidth,'stroke-linecap':'round','stroke-linejoin':'round','fill':fill}">
      <foreignObject style="overflow:visible;" pointer-events="all" :width="((detail && detail.style && detail.style.position && detail.style.position.w) || 200) - ((detail && detail.style && detail.style.borderWidth) || 0)*2" :height="((detail && detail.style && detail.style.position && detail.style.position.h) || 200) - ((detail && detail.style && detail.style.borderWidth) || 0)*2">
        <div class="view-chart-gauge" :ref="detail && detail.identifier ? detail.identifier : 'chart_default'" :style="{'overflow': 'visible','width':(detail && detail.style && detail.style.position && detail.style.position.w) || '200px','height':(detail && detail.style && detail.style.position && detail.style.position.h) || '200px',}">
            Click to bind data.
        </div>
      </foreignObject>
      <!--      闪烁-->
      <animate v-if="isStart&&animateType.includes('blink')&&!IsToolBox" attributeName="opacity"
               values="0.1;1;0.1" :dur="blinkSpeed+'s'"
               repeatCount="indefinite"/>
      <!--渐变-->
      <animate v-if="isStart&&animateType.includes('millcolorGrad')&&!IsToolBox" attributeName="fill"
               :values="startColor+';'+stopColor+';'+startColor" :dur="animateSpeed+'s'"
               repeatCount="indefinite"/>
      <!--缩放      -->
      <animateTransform v-if="isStart&&animateType.includes('Zoom')&&!IsToolBox" attributeName="transform"   begin="0s" dur="0.6s" type="scale" values="0.9;1;0.9" repeatCount="indefinite"/>
      <!--      顺时针旋转-->
      <animateTransform v-if="isStart&&animateType.includes('animateSpin')&&!IsToolBox&&spinDirection==0" attributeType="XML" attributeName="transform" :dur="animateSpinSpeed+'s'" type="rotate" from="0 0 0" to="360 0 0" repeatCount="indefinite" />
      <!--      逆时针旋转-->
      <animateTransform v-if="isStart&&animateType.includes('animateSpin')&&!IsToolBox&&spinDirection==1" attributeType="XML" attributeName="transform" :dur="animateSpinSpeed+'s'" type="rotate" from="360 0 0" to="0 0 0" repeatCount="indefinite" />
  </g>
</svg>
</template>

<script>
import * as echarts from 'echarts';
import BaseView from '../../View';
import ISMChildAutoMixin from '@/mixins/ISMChildAutoMixin'
export default {
  mixins: [ISMChildAutoMixin],
  name: 'ism-view-chart-gauge-2',
  inject: ['getNode'],
  props: {

  },
  watch: {
    detail: {
      handler(newVal, oldVal) {
        if(this.editMode){
          this.initComponents(newVal)
        }
        this.onResize()
      },
      deep: true
    }
  },
  data() {
    return {
      ShowDataResult:0,
      detail:{},
      IsToolBox:false,
      editMode:true,
        base:{
          "text": "configComponent.chartGauge.progressGauge",
          "icon": "data:image/png;base64,",
          "isFontIcon": true,
          "info": {
            "type": "chart-gauge",
            "action": [],
            "active": [
              {
                id:"ShowData",
                name:"configComponent.ChartPublic.ShowData",
                result:"",
                isExpression:false,
                condition:{
                  deviceSN:"",
                  selectVideoType:0,
                  isBandDevice:false,
                  bandType:1,
                  dataID: "",
                  dataName: "",
                  operator:"",
                  OperatorValue:"",
                  OperatorMaxValue:"",
                },
              }
            ],
            "dataBind": [],
            "animate": {
              "selected": [],
              "condition":{
                deviceSN:"",
                selectVideoType:0,
                isBandDevice:false,
                bandType:1,
                dataID: "",
                dataName: "",
                operator:"",
                OperatorValue:"",
                OperatorMaxValue:"",
              },
              "isExpression": false,
              "animateList": [
                {
                  id: "blink",
                  name: "component.public.animateBlink",
                },
                {
                  id: "Zoom",
                  name: "component.public.Zoom",
                },
                {
                  id: "animateSpin",
                  name: "component.public.animateSpin",
                },
              ],
              "animateElement": [
                {
                  id: "blink",
                  elementList:[
                    {
                      "name":"component.public.animateSpeed",
                      "type":7,
                      "value":1,
                      "min":0.1,
                      "key":"blinkSpeed",
                    },
                  ]
                },
                {
                  id: "millcolorGrad",
                  elementList:[
                    {
                      "name": "component.public.startColor",
                      "type": 2,
                      "value": "#74f808",
                      "key": "startColor",
                    },
                    {
                      "name": "component.public.stopColor",
                      "type": 2,
                      "value": "#f30b0b",
                      "key": "stopColor",
                    },
                    {
                      "name":"component.public.animateSpeed",
                      "type":7,
                      "value":1,
                      "min":0.1,
                      "key":"animateSpeed",
                    },
                  ]
                },
                {
                  id: "animateSpin",
                  elementList:[
                    {
                      "name":"component.public.animateSpinSpeed",
                      "type":7,
                      "value":1,
                      "min":0.1,
                      "key":"spinSpeed",
                    },
                    {
                      name:"configComponent.bigScreen.border.border89Direction",
                      type:6,
                      value:0,
                      enumList:[
                        {
                          value:0,
                          option:"configComponent.bigScreen.border.border89DirectionForward"
                        },
                        {
                          value:1,
                          option:"configComponent.bigScreen.border.border89DirectionNegative"
                        }
                      ],
                      min:1,
                      key:"spinDirection",
                    }
                  ]
                },
              ],
            },
            "style": {
              "position": {
                "x": 0,
                "y": 0,
                "w": 342,
                "h": 300
              },
              "backColor": "transparent",
              "zIndex": 1,
              "transform": 0,
              "diy":[
                {
                  "name":"configComponent.ChartPublic.ChartTitle",
                  "type":4,
                  "value":"Title",
                  "key":"ChartTitle",
                },
                {
                  "name":"configComponent.ChartPublic.ChartUnit",
                  "type":4,
                  "value":"%",
                  "key":"ChartUnit",
                },
                {
                  "name":"configComponent.ChartPublic.ChartTitleFontSize",
                  "type":1,
                  "value":20,
                  "key":"ChartTitleFontSize",
                },
                {
                  "name":"configComponent.ChartPublic.ChartTitleFontColor",
                  "type":2,
                  "value":"#000000",
                  "key":"ChartTitleFontColor",
                },
                {
                  "name":"configComponent.ChartPublic.ChartMinValue",
                  "type":7,
                  "value":0,
                  "key":"ChartMinValue",
                },
                {
                  "name":"configComponent.ChartPublic.ChartMaxValue",
                  "type":7,
                  "value":100,
                  "key":"ChartMaxValue",
                },
                {
                  "name":"configComponent.ChartPublic.ChartAxisTickColor",
                  "type":2,
                  "value":"#000000",
                  "key":"ChartAxisTickColor",
                },
                {
                  "name":"configComponent.ChartPublic.ChartSplitLineColor",
                  "type":2,
                  "value":"#000000",
                  "key":"ChartSplitLineColor",
                },
                {
                  "name":"configComponent.ChartPublic.ChartPointerColor",
                  "type":2,
                  "value":"#58D9F9",
                  "key":"ChartPointerColor",
                },
                {
                  "name":"configComponent.ChartPublic.ChartWidth",
                  "type":7,
                  "value":20,
                  "key":"ChartWidth",
                },
                {
                  "name":"configComponent.ChartPublic.LabelDis",
                  "type":7,
                  "value":25,
                  "key":"LabelDis",
                },
                {
                  "name":"configComponent.ChartPublic.splitNumber",
                  "type":1,
                  "value":10,
                  "key":"splitNumber",
                },
              ]
            }
          }
        },
        strokeColor:"#000000",
        fill:"#A1BFE2",
        strokeWidth:0.3,
        fillOpacity:1,
        strokeOpacity:1,
        animateType:"blink",
        startColor:"#74f808",
        stopColor:"#74f808",
        animateSpeed:0.5,
        animateSpinSpeed:0.5,
        spinDirection:0,
        blinkSpeed:0.5,
        isStart:false,
        eventValue: '0.00',
        eventUnit: '',
        chartUnit:"",
        option: {
          tooltip: {
            formatter: '{a} <br/>{b} : {c}%'
          },
          series: [
          {
            name: 'Pressure',
            type: 'gauge',
            startAngle: 180,
            endAngle: 0,
            min:-20,
            max: 40,
            splitNumber: 12,
            progress: {
              show: true,
              roundCap: true,
              width: 18
            },
            itemStyle: {
              color: '#58D9F9',
              shadowColor: 'rgba(0,138,255,0.45)',
              shadowBlur: 10,
              shadowOffsetX: 2,
              shadowOffsetY: 2
            },
            pointer: {
              icon: 'path://M2090.36389,615.30999 L2090.36389,615.30999 C2091.48372,615.30999 2092.40383,616.194028 2092.44859,617.312956 L2096.90698,728.755929 C2097.05155,732.369577 2094.2393,735.416212 2090.62566,735.56078 C2090.53845,735.564269 2090.45117,735.566014 2090.36389,735.566014 L2090.36389,735.566014 C2086.74736,735.566014 2083.81557,732.63423 2083.81557,729.017692 C2083.81557,728.930412 2083.81732,728.84314 2083.82081,728.755929 L2088.2792,617.312956 C2088.32396,616.194028 2089.24407,615.30999 2090.36389,615.30999 Z',
              length: '75%',
              width: 16,
              offsetCenter: [0, '5%']
            },
            axisLine: {
              roundCap: true,
              lineStyle: {
                width: 18
              }
            },
            radius: "110%",
            center : ['50%', '60%'],    // 默认全局居中
            title: {
              show: false,
              textStyle: {
                fontSize: 10,
                color: '#ffffff'
              }
            },
            axisTick: {
              lineStyle: {
                width: 2,
                color: '#080808'
              },
            },
            splitLine: {
              show:true,
              lineStyle: {
                width: 2,
                color: '#f40404'
              }
            },
            axisLabel: {
              show: true,
              distance: 30,
              color: "#ffffff",
              fontSize:12,
              formatter: function (val) {
                //解决刻度的值为浮点数问题
                return Math.ceil(val);
              },
            },
            detail: {
              offsetCenter: [0, '35%'],
              valueAnimation: true,
              formatter: null,
              color: "#f512d3",
              fontSize: 12,
              rich: {
                value: {
                  fontSize: 50,
                  fontWeight: 'bolder',
                  color: '#777'
                },
                unit: {
                  fontSize: 20,
                  color: '#999',
                  padding: [0, 0, -20, 10]
                }
              }
            },
            data: [
              {
                value: 0,
                name: ''
              }
            ]
          }]
        }
      }
  },
  beforeDestroy () {
    if (this.echartsView != null&&(typeof this.echartsView.dispose=="function")) {
      this.echartsView.dispose()
    }
  },
  methods: {
    formatter(value){
      return '{value|' + value.toFixed(0) + '}{unit|'+this.chartUnit+'}';
    },
    initComponents(option){
      if(this.IsToolBox)
      {
        return
      }
      // 确保 option 存在
      if (!option || !option.style) {
        console.warn('Chart initComponents: option or option.style is undefined')
        return
      }
      let refObj = this.detail && this.detail.identifier ? this.detail.identifier : 'chart_' + Date.now()
      let view = this.$refs[refObj]
      // 确保 DOM 元素存在
      if (!view) {
        console.warn('Chart initComponents: cannot find DOM element with ref:', refObj)
        return
      }
      let i=0
      this.option.series[0].detail.formatter = this.formatter

      for( i=0;i<option.style.diy.length;i++)
      {
        if(option.style.diy[i].key=="ChartTitle")
        {
          this.option.series[0].data[0].name=option.style.diy[i].value
        }
        else if(option.style.diy[i].key=="ChartUnit")
        {
          this.chartUnit = option.style.diy[i].value
          this.option.tooltip.formatter = '{a} <br/>{b} : {c}'+this.chartUnit
        }
        else if(option.style.diy[i].key=="ChartTitleFontSize")
        {
          this.option.series[0].title.textStyle.fontSize = option.style.diy[i].value
          this.option.series[0].axisLabel.fontSize = option.style.diy[i].value
          this.option.series[0].detail.fontSize = option.style.diy[i].value
          this.option.series[0].detail.rich.value.fontSize = option.style.diy[i].value
          this.option.series[0].detail.rich.unit.fontSize = option.style.diy[i].value-5>0?option.style.diy[i].value-5:option.style.diy[i].value
        }
        else if(option.style.diy[i].key=="ChartTitleFontColor")
        {
          this.option.series[0].title.textStyle.color = option.style.diy[i].value
          this.option.series[0].detail.color = option.style.diy[i].value
          this.option.series[0].detail.rich.value.color = option.style.diy[i].value
          this.option.series[0].detail.rich.unit.color = option.style.diy[i].value
          this.option.series[0].axisLabel.color = option.style.diy[i].value
        }
        else if(option.style.diy[i].key=="ChartMinValue")
        {
          this.option.series[0].min = option.style.diy[i].value
        }
        else if(option.style.diy[i].key=="ChartMaxValue")
        {
          this.option.series[0].max = option.style.diy[i].value
        }
        else if(option.style.diy[i].key=="ChartAxisTickColor")
        {
          this.option.series[0].axisTick.lineStyle.color = option.style.diy[i].value
        }
        else if(option.style.diy[i].key=="ChartSplitLineColor")
        {
          this.option.series[0].splitLine.lineStyle.color = option.style.diy[i].value
        }
        else if(option.style.diy[i].key=="ChartPointerColor")
        {
          this.option.series[0].itemStyle.color = option.style.diy[i].value
        }
        else if(option.style.diy[i].key=="ChartSplitTickColor")
        {
          this.option.series[0].axisLine.lineStyle.color = JSON.parse(option.style.diy[i].value)
        }
        else if(option.style.diy[i].key=="ChartWidth")
        {
          this.option.series[0].axisLine.lineStyle.width = parseInt(option.style.diy[i].value)
        }
        else if(option.style.diy[i].key=="LabelDis")
        {
          this.option.series[0].axisLabel.distance = parseInt(option.style.diy[i].value)
        }
        else if(option.style.diy[i].key=="splitNumber")
        {
          this.option.series[0].splitNumber = parseInt(option.style.diy[i].value)
        }
      }
      i=0
      this.animateType = option.animate.selected
      if(option.animate.isExpression)
      {
        this.isStart = false
      }
      else
      {
        this.isStart = true
      }
      for( i=0;i<option.animate.animateElement.length;i++)
      {
        if(option.animate.animateElement[i].id=="millcolorGrad")
        {
          for(let k =0;k<option.animate.animateElement[i].elementList.length;k++)
          {
            if(option.animate.animateElement[i].elementList[k].key=="startColor")
            {
              this.startColor=option.animate.animateElement[i].elementList[k].value
            }
            else if(option.animate.animateElement[i].elementList[k].key=="stopColor")
            {
              this.stopColor=option.animate.animateElement[i].elementList[k].value
            }
            else if(option.animate.animateElement[i].elementList[k].key=="animateSpeed")
            {
              this.animateSpeed=option.animate.animateElement[i].elementList[k].value
            }
          }
        }
        else if(option.animate.animateElement[i].id=="blink")
        {
          for(let k =0;k<option.animate.animateElement[i].elementList.length;k++) {
            if (option.animate.animateElement[i].elementList[k].key == "blinkSpeed") {
              this.blinkSpeed = option.animate.animateElement[i].elementList[k].value
            }
          }
        }
        else if(option.animate.animateElement[i].id=="animateSpin")
        {
          for(let k =0;k<option.animate.animateElement[i].elementList.length;k++) {
            if (option.animate.animateElement[i].elementList[k].key == "spinSpeed") {
              this.animateSpinSpeed = option.animate.animateElement[i].elementList[k].value
            }
            else if (option.animate.animateElement[i].elementList[k].key == "spinDirection") {
              this.spinDirection = option.animate.animateElement[i].elementList[k].value
            }
          }
        }
      }

      if (!this.echartsView) {
        this.echartsView = echarts.init(view, null);
      }
      else
      {
        this.echartsView.resize()
      }
      let _t = this
      // this.option.series[0].itemStyle.normal.color = this.progressColor
      setTimeout(function (){
        _t.echartsView.setOption(_t.option,true)
        _t.echartsView.resize()
      }, 20)
    },
    onResize() {
        if (this.echartsView) {
            this.echartsView.resize();
        }
    },
    updateView() {
          this.setOption(this.option);
      },
  },
  created(){
    let _t = this
    const node = this.getNode()
    node.on('change:data', ({ current }) => {
      if(current) {
        _t.detail = current.detail
      }
    })
    node.on('change:size', ({ current }) => {
      _t.detail.style.position.w = current.width
      _t.detail.style.position.h = current.height
    });
    node.on('change:visible', ({ current }) => {
      if(current)
      {
        _t.option.series[0].data[0].value =_t.ShowDataResult
        _t.initComponents(_t.detail);
      }
    });
    this.detail = node.getData().detail
    this.editMode = node.getData().editMode
    this.showDeviceUuid = node.getData().showDeviceUuid
    this.IsToolBox = node.getData().IsToolBox
    _t.$EventBus.$on('cell-editMode', (data) => {
      _t.editMode = data.edit
      _t.IsToolBox = data.toolbox
      // _t.initComponents(_t.detail);
    })
  },
  mounted() {
      let _t = this
      this.$nextTick(function(){
        this.initComponents(this.detail);
        let activeEvent = this.detail.identifier+"activeEvent"//动作数据
        let animateEvent = this.detail.identifier+"animateEvent"//动作数据

        _t.$EventBus.$on(activeEvent, (data) => {
          if(data.ID == "ShowData")
          {
            this.ShowDataResult = data.result
            this.option.series[0].data[0].value = data.result
            this.echartsView.setOption(this.option, true);
          }
        })
        _t.$EventBus.$on(animateEvent, (data) => {
          _t.isStart = data
        })
      });
    }
}
</script>

<style lang="less">
.view-chart-gauge {
    height: 100%;
    width: 100%;
}
</style>
